mapper.select:
SELECT A.* FROM ( SELECT HD.BUYER_CD , HD.BID_NUM , HD.BID_CNT , HD.ANN_NO , (CASE WHEN HD.BID_STATUS IN ('2303', '2330') THEN '[취소]' || HD.ANN_ITEM ELSE HD.ANN_ITEM END ) AS ANN_ITEM , HD.ANN_DATE , HD.CONT_TYPE1 , HD.CONT_TYPE2 , HD.CONT_TYPE3 , SUBSTR(HD.APP_BEGIN_DATE, 1, 4) '-' SUBSTR(HD.APP_BEGIN_DATE, 5, 2) '-' SUBSTR(HD.APP_BEGIN_DATE, 7, 2) ' ' SUBSTR(HD.APP_BEGIN_TIME, 1, 2) ':' SUBSTR(HD.APP_BEGIN_TIME, 3, 2) AS APP_BEGIN_DATETIME , SUBSTR(HD.APP_END_DATE, 1, 4) '-' SUBSTR(HD.APP_END_DATE, 5, 2) '-' SUBSTR(HD.APP_END_DATE, 7, 2) ' ' SUBSTR(HD.APP_END_TIME, 1, 2) ':' SUBSTR(HD.APP_END_TIME, 3, 2) AS APP_END_DATETIME ,GETCOMCODE(HD.GATE_CD, 'M044', HD.ANNO_OPEN_FLAG, 0, #{ses.langCd}) ' (' GETCOMCODE(HD.GATE_CD, 'M044', (HD.ANNO_FLAG, '0'), 0, #{ses.langCd}) ')' AS ANNO_LOC ,GETCOMCODE(HD.GATE_CD, 'M044', HD.PROP_OPEN_FLAG, 0, #{ses.langCd}) ' (' GETCOMCODE(HD.GATE_CD, 'M044', (HD.PROP_FLAG, '0'), 0, #{ses.langCd}) ')' AS PROP_LOC ,(CASE WHEN AP.GUAR_ATT_FILE_NUM IS NULL THEN '' ELSE TO_CHAR(GETFILECOUNT(AP.GATE_CD, AP.GUAR_ATT_FILE_NUM)) END) AS GUAR_CNT ,getSupBidAnnProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'CD') AS APP_FLAG -- 공급사 입찰참가신청 상태명 변경 (기존 : 신청, 미신청 => 신청대기, 신청중) --,getSupBidAnnProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'LOC') AS APP_FLAG_LOC ,(CASE WHEN getSupBidAnnProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'CD') = '100' THEN '예정' WHEN getSupBidAnnProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'CD') = '200' THEN '진행' ELSE '' END) AS APP_FLAG_LOC ,(CASE WHEN AP.APP_DATE IS NULL THEN 'N' ELSE 'Y' END) AS APP_INFO , AP.APP_DATE AS AP_APP_DATE , HD.ANNO_OPEN_FLAG , HD.ANNO_FLAG , HD.PROP_OPEN_FLAG , HD.PROP_FLAG , AP.BID_GUAR_TYPE , AP.GUAR_ATT_FILE_NUM , AP.GUAR_REQ_NUM , (CASE WHEN AP.GUAR_NUM IS NULL THEN '' ELSE (SUBSTR(AP.GUAR_NUM, 7, 18), '') END) AS GUAR_NUM , HD.BID_STATUS AS ORI_BID_STATUS ,(CASE WHEN HD.CONT_TYPE1 = 'NC' -- 지명경쟁 THEN (CASE WHEN (SELECT COUNT(P.VENDOR_CD) FROM STOCBDAP P WHERE P.GATE_CD = HD.GATE_CD AND P.BUYER_CD = HD.BUYER_CD AND P.BID_NUM = HD.BID_NUM AND P.BID_CNT = HD.BID_CNT AND P.VENDOR_CD = #{ses.companyCd} AND P.DEL_FLAG = '0') > 0 THEN '1' -- 지명경쟁인 경우 지명된 협력사만 보이도록 함 ELSE '0' END) ELSE (CASE WHEN (SELECT COUNT(P.VENDOR_CD) FROM STOCVNCM P WHERE P.GATE_CD = HD.GATE_CD AND P.BUYER_CD = HD.BUYER_CD AND P.VENDOR_CD = #{ses.companyCd} AND P.CONFIRM_FLAG = 'E' AND P.DEL_FLAG = '0') > 0 THEN '1' -- 지명경쟁이 아닌 경우 거래희망고객사에 승인된 협력사만 보이도록 함 ELSE '0' END) END) AS AP_INCLUDE_FLAG ,(CASE WHEN SYSDATE BETWEEN TO_DATE(HD.APP_BEGIN_DATE HD.APP_BEGIN_TIME, 'YYYYMMDDHH24MISS') AND TO_DATE(HD.APP_END_DATE HD.APP_END_TIME, 'YYYYMMDDHH24MISS') THEN 'Y' ELSE 'N' END) AS APPLY_POSSIBLE_FLAG FROM STOCBDHD HD LEFT JOIN STOCBDAP AP ON (HD.GATE_CD = AP.GATE_CD AND HD.BUYER_CD = AP.BUYER_CD AND HD.BID_NUM = AP.BID_NUM AND HD.BID_CNT = AP.BID_CNT AND AP.VENDOR_CD = #{ses.companyCd} AND AP.DEL_FLAG = '0') WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BID_STATUS != '9999' AND HD.SIGN_STATUS = 'E' AND ((SYSDATE, 'YYYYMMDD') >= HD.ANN_DATE AND SYSDATE < (HD.APP_END_DATE HD.APP_END_TIME, 'YYYYMMDDHH24MISS')) AND HD.DEL_FLAG = '0'
AND (HD.APP_END_DATE HD.APP_END_TIME) >= #{ANN_DATE_FROM} '000000' AND (HD.APP_END_DATE HD.APP_END_TIME) <= #{ANN_DATE_TO} '235959'
AND getSupBidAnnProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'CD') = #{APP_FLAG}
AND UPPER(HD.ANN_NO) LIKE '%' UPPER(#{ANN_NO}) '%'
AND UPPER(HD.ANN_ITEM) LIKE '%' UPPER(#{ANN_ITEM}) '%'
) A WHERE A.AP_INCLUDE_FLAG = '1' ORDER BY A.BID_NUM, A.BID_CNT

mapper.insert:
        MERGE  STOCBDAP BDAP
        USING (SELECT
                     #{ses.gateCd} AS GATE_CD
                    ,#{BUYER_CD}   AS BUYER_CD
                    ,#{BID_NUM}    AS BID_NUM
                    ,#{BID_CNT}    AS BID_CNT
                    ,#{VENDOR_CD}  AS VENDOR_CD
                ) B
	         ON (BDAP.GATE_CD   = B.GATE_CD
	         AND BDAP.BUYER_CD  = B.BUYER_CD
	         AND BDAP.BID_NUM   = B.BID_NUM
	         AND BDAP.BID_CNT   = B.BID_CNT
	         AND BDAP.VENDOR_CD = B.VENDOR_CD)
        WHEN MATCHED THEN
        UPDATE SET
             MOD_DATE = SYSDATE
            ,MOD_USER_ID = #{ses.userId}
            ,BID_GUAR_AMT = #{BID_GUAR_AMT}
            ,GUAR_AMT_CERTV = #{GUAR_AMT_CERTV}
            ,VID_RANDOM = #{VID_RANDOM}
            ,GUAR_AMT_DET_CERTV = #{GUAR_AMT_DET_CERTV}
            ,GUAR_AMT_CERTNUM = #{GUAR_AMT_CERTNUM}
            ,BID_GUAR_TYPE = #{BID_GUAR_TYPE}
            ,GUARANTEER = #{GUARANTEER}
            ,GUAR_NUM = #{GUAR_NUM}
            ,GUAR_ATT_FILE_NUM = #{GUAR_ATT_FILE_NUM}
            ,APP_DATE = TO_CHAR(SYSDATE, 'YYYYMMDD')
            ,APP_TIME = TO_CHAR(SYSDATE, 'HH24MISS')
            ,APP_ATT_FILE_NUM = #{APP_ATT_FILE_NUM}
            ,VENDOR_PIC_USER_NM = #{VENDOR_PIC_USER_NM}
            ,VENDOR_PIC_USER_CELL_NUM = #{VENDOR_PIC_USER_CELL_NUM}
            ,VENDOR_PIC_USER_EMAIL = #{VENDOR_PIC_USER_EMAIL}
        WHEN NOT MATCHED THEN
        INSERT (
             GATE_CD
            ,BUYER_CD
            ,BID_NUM
            ,BID_CNT
            ,VENDOR_CD
            ,REG_DATE
            ,REG_USER_ID
            ,MOD_DATE
            ,MOD_USER_ID
            ,DEL_FLAG
            ,BID_GUAR_AMT
            ,GUAR_AMT_CERTV
            ,VID_RANDOM
            ,GUAR_AMT_DET_CERTV
            ,GUAR_AMT_CERTNUM
            ,BID_GUAR_TYPE
            ,GUARANTEER
            ,GUAR_NUM
            ,GUAR_ATT_FILE_NUM
            ,APP_DATE
            ,APP_TIME
            ,APP_ATT_FILE_NUM
            ,VENDOR_PIC_USER_NM
            ,VENDOR_PIC_USER_CELL_NUM
			,VENDOR_PIC_USER_EMAIL
        ) VALUES (
             #{ses.gateCd}
            ,#{BUYER_CD}
            ,#{BID_NUM}
            ,#{BID_CNT}
            ,#{VENDOR_CD}
            ,SYSDATE
            ,#{ses.userId}
            ,SYSDATE
            ,#{ses.userId}
            ,'0'
            ,#{BID_GUAR_AMT}
            ,#{GUAR_AMT_CERTV}
            ,#{VID_RANDOM}
            ,#{GUAR_AMT_DET_CERTV}
            ,#{GUAR_AMT_CERTNUM}
            ,#{BID_GUAR_TYPE}
            ,#{GUARANTEER}
            ,#{GUAR_NUM}
            ,#{GUAR_ATT_FILE_NUM}
            ,TO_CHAR(SYSDATE, 'YYYYMMDD')
            ,TO_CHAR(SYSDATE, 'HH24MISS')
            ,#{APP_ATT_FILE_NUM}
            ,#{VENDOR_PIC_USER_NM}
			,#{VENDOR_PIC_USER_CELL_NUM}
			,#{VENDOR_PIC_USER_EMAIL}
        )

mapper.delete:
DELETE FROM STOCBDAP
 WHERE GATE_CD   = #{ses.gateCd}
   AND BUYER_CD  = #{BUYER_CD}
   AND BID_NUM   = #{BID_NUM}
   AND BID_CNT   = #{BID_CNT}
   AND VENDOR_CD = #{VENDOR_CD}

mapper.select:
SELECT A.* FROM ( SELECT HD.GATE_CD , HD.BUYER_CD , HD.BID_NUM , HD.BID_CNT , AP.VENDOR_CD , PG.VOTE_CNT , HD.BID_STATUS AS ORI_BID_STATUS ,getSupBidProgressCd(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, PG.VOTE_CNT, AP.VENDOR_CD, 'CD') AS BID_STATUS ,(CASE WHEN (SELECT COUNT(VO.VENDOR_CD) FROM STOCBDVO VO WHERE VO.GATE_CD = AP.GATE_CD AND VO.BUYER_CD = AP.BUYER_CD AND VO.BID_NUM = AP.BID_NUM AND VO.BID_CNT = AP.BID_CNT AND VO.VOTE_CNT = PG.VOTE_CNT AND VO.VENDOR_CD = AP.VENDOR_CD AND VO.DEL_FLAG = '0') > 0 THEN 'Y' ELSE 'N' END) AS SEND_FLAG ,(CASE WHEN (SELECT COUNT(VO.VENDOR_CD) FROM STOCBDVO VO WHERE VO.GATE_CD = AP.GATE_CD AND VO.BUYER_CD = AP.BUYER_CD AND VO.BID_NUM = AP.BID_NUM AND VO.BID_CNT = AP.BID_CNT AND VO.VOTE_CNT = PG.VOTE_CNT AND VO.VENDOR_CD = AP.VENDOR_CD AND VO.DEL_FLAG = '0') > 0 THEN 'N' ELSE (CASE WHEN HD.CONT_TYPE2 = 'TD' THEN (CASE WHEN AP.EV_FINAL_FLAG = '600' THEN 'N' ELSE 'Y' END) ELSE 'Y' END) END) AS SEND_POSSIBLE_FLAG ,(SELECT V.VOTE_CNT FROM (SELECT VOTE_CNT, RANK() OVER (PARTITION BY PG.GATE_CD, PG.BUYER_CD, PG.BID_NUM, PG.BID_CNT ORDER BY PG.MOD_DATE DESC) AS RANK FROM STOCBDPG PG WHERE PG.GATE_CD = HD.GATE_CD AND PG.BUYER_CD = HD.BUYER_CD AND PG.BID_NUM = HD.BID_NUM AND PG.BID_CNT = HD.BID_CNT AND PG.DEL_FLAG = '0') V WHERE V.RANK = 1) AS PRECENT_VOTE FROM STOCBDHD HD JOIN STOCBDAP AP ON (HD.GATE_CD = AP.GATE_CD AND HD.BUYER_CD = AP.BUYER_CD AND HD.BID_NUM = AP.BID_NUM AND HD.BID_CNT = AP.BID_CNT AND AP.VENDOR_CD = #{ses.companyCd} AND (AP.FINAL_FLAG, '100') != '600' AND (AP.EV_FINAL_FLAG, '100') != '600' AND AP.DEL_FLAG = '0') LEFT JOIN STOCBDPG PG ON (HD.GATE_CD = PG.GATE_CD AND HD.BUYER_CD = PG.BUYER_CD AND HD.BID_NUM = PG.BID_NUM AND HD.BID_CNT = PG.BID_CNT AND PG.DEL_FLAG = '0') WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{BUYER_CD} AND HD.BID_NUM = #{BID_NUM} AND HD.BID_CNT = #{BID_CNT} AND HD.BID_STATUS NOT IN ('1300', '2500', '9999') AND HD.SIGN_STATUS = 'E' AND HD.DEL_FLAG = '0' ) A
WHERE (CASE WHEN (TO_NUMBER(A.ORI_BID_STATUS) < 2400 OR A.ORI_BID_STATUS = '2550') THEN '1' WHEN (A.ORI_BID_STATUS = '2410' AND (SELECT MAX((SV.BID_STATUS, '100')) FROM STOCBDVO SV WHERE SV.GATE_CD = A.GATE_CD AND SV.BUYER_CD = A.BUYER_CD AND SV.BID_NUM = A.BID_NUM AND SV.BID_CNT = A.BID_CNT AND SV.VENDOR_CD = A.VENDOR_CD AND SV.DEL_FLAG = '0') = '200' AND A.VOTE_CNT <= PRECENT_VOTE) THEN '1' ELSE '0' END) = '1'
AND A.VOTE_CNT = #{VOTE_CNT}

        SELECT
              ROWNUM AS SEND_CNT
            ,(CASE WHEN (VO.CHOICE_ESTM_NUM1 = #{CHOICE_ESTM_NUM1} OR VO.CHOICE_ESTM_NUM1 = #{CHOICE_ESTM_NUM2}) THEN 'Y' ELSE 'N' END) AS SAME_FLAG1
            , VO.CHOICE_ESTM_NUM1 AS CHOICE_ESTM_NUM1
            ,(CASE WHEN (VO.CHOICE_ESTM_NUM2 = #{CHOICE_ESTM_NUM1} OR VO.CHOICE_ESTM_NUM2 = #{CHOICE_ESTM_NUM2}) THEN 'Y' ELSE 'N' END) AS SAME_FLAG2
	        , VO.CHOICE_ESTM_NUM2 AS CHOICE_ESTM_NUM2
          FROM STOCBDVO VO
         WHERE VO.GATE_CD  = #{ses.gateCd}
           AND VO.BUYER_CD = #{BUYER_CD}
           AND VO.BID_NUM  = #{BID_NUM}
           AND VO.BID_CNT  = #{BID_CNT}
           AND VO.VOTE_CNT = #{VOTE_CNT}
           AND VO.VENDOR_CD <> #{VENDOR_CD}
           AND VO.DEL_FLAG = '0'

SELECT (CASE WHEN (ADJ_PRC_STATUS = '100' OR ADJ_PRC_STATUS = '150' OR ADJ_PRC_STATUS = '300') THEN 'Y' ELSE 'N' END)
  FROM STOCBDVO
 WHERE GATE_CD   = #{ses.gateCd}
   AND BUYER_CD  = #{BUYER_CD}
   AND BID_NUM   = #{BID_NUM}
   AND BID_CNT   = #{BID_CNT}
   AND VOTE_CNT  = #{VOTE_CNT}
   AND VENDOR_CD = #{VENDOR_CD}
   AND DEL_FLAG  = '0'

mapper.update:
UPDATE STOCBDVO SET
      MOD_DATE       = SYSDATE
    , MOD_USER_ID    = #{ses.userId}
    , ADJ_PRC_STATUS = (CASE WHEN #{ADJ_PRC_STATUS} = 'T' THEN '150' ELSE '200' END)
    , ADJ_VID_RANDOM = #{ADJ_VID_RANDOM}
    , ADJ_CERTV      = #{ADJ_CERTV}
 WHERE GATE_CD   = #{ses.gateCd}
   AND BUYER_CD  = #{BUYER_CD}
   AND BID_NUM   = #{BID_NUM}
   AND BID_CNT   = #{BID_CNT}
   AND VOTE_CNT  = #{VOTE_CNT}
   AND VENDOR_CD = #{VENDOR_CD}

UPDATE STOCBDVD SET
      MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , PR_QT = #{PR_QT}
    , UNIT_PRC = #{UNIT_PRC}
    , PR_AMT = #{PR_AMT}
    , TCO_AMT = #{TCO_AMT}
    , SW_BUS_AMT = #{SW_BUS_AMT}
    , MNT_SANGJU_YN = #{MNT_SANGJU_YN}
    , CONSUMER_AMT = #{CONSUMER_AMT}
    , FC_MNT_TERM = #{FC_MNT_TERM}
    , CH_RATE = #{CH_RATE}
    , DOIB_AMOUNT = #{DOIB_AMOUNT}
    , MNT_RATE = #{MNT_RATE}
    , MNT_SDAY = (#{MNT_SDAY}, 'YYYYMMDD')
    , MNT_EDAY = (#{MNT_EDAY}, 'YYYYMMDD')
    , MNT_GUR_MONTH = #{MNT_GUR_MONTH}
    , RT_INSP_PERIOD = #{RT_INSP_PERIOD}
    , FALT_RC_TG_TIME = #{FALT_RC_TG_TIME}
    , ATT_FILE_NUM = #{VENDOR_ATT_FILE_NUM}
    , ITEM_RMK = #{VENDOR_ITEM_RMK}
 WHERE GATE_CD   = #{ses.gateCd}
   AND BUYER_CD  = #{BUYER_CD}
   AND BID_NUM   = #{BID_NUM}
   AND BID_CNT   = #{BID_CNT}
   AND VOTE_CNT  = #{VOTE_CNT}
   AND VENDOR_CD = #{VENDOR_CD}
   AND ITEM_SQ   = #{ITEM_SQ}

mapper.select:
SELECT A.ANN_NO, A.BID_CNT, A.ANN_ITEM ,A.CONT_TYPE1, A.CONT_TYPE2, A.CONT_TYPE3, A.VOTE_CNT ,A.BID_BEGIN_DATETIME, A.BID_END_DATETIME ,A.SETTLE_FLAG, A.SETTLE_VENDOR_CD, A.SETTLE_VENDOR_NM, A.SETTLE_AMT ,A.BID_AMT, A.RMK ,A.BID_STATUS, A.BID_STATUS_LOC, A.ADJ_PRC_STATUS ,A.BUYER_CD, A.BID_NUM FROM ( SELECT HD.BUYER_CD , HD.BID_NUM , HD.BID_CNT , VO.VOTE_CNT , HD.ANN_NO , HD.ANN_ITEM , HD.CONT_TYPE1 , HD.CONT_TYPE2 , HD.CONT_TYPE3 , SUBSTR(PG.BID_BEGIN_DATE, 1, 4) '-' SUBSTR(PG.BID_BEGIN_DATE, 5, 2) '-' SUBSTR(PG.BID_BEGIN_DATE, 7, 2) ' ' SUBSTR(PG.BID_BEGIN_TIME, 1, 2) ':' SUBSTR(PG.BID_BEGIN_TIME, 3, 2) AS BID_BEGIN_DATETIME , SUBSTR(PG.BID_END_DATE, 1, 4) '-' SUBSTR(PG.BID_END_DATE, 5, 2) '-' SUBSTR(PG.BID_END_DATE, 7, 2) ' ' SUBSTR(PG.BID_END_TIME, 1, 2) ':' SUBSTR(PG.BID_END_TIME, 3, 2) AS BID_END_DATETIME ,(CASE WHEN VO.BID_STATUS = '300' THEN 'Y' ELSE 'N' END) AS SETTLE_FLAG , VO.BID_AMT ,(CASE WHEN HD.RLT_SIGN_STATUS = 'E' THEN '유찰' ELSE '' END) AS RMK , HD.BID_STATUS ,GETCOMCODE(HD.GATE_CD, 'M340', HD.BID_STATUS, 0, #{ses.langCd}) AS BID_STATUS_LOC , VO.ADJ_PRC_STATUS ,NVL((SELECT GL.VENDOR_CD FROM STOCBDVO S LEFT JOIN STOCVNGL GL ON (S.GATE_CD = GL.GATE_CD AND S.VENDOR_CD = GL.VENDOR_CD) WHERE S.GATE_CD = HD.GATE_CD AND S.BUYER_CD = HD.BUYER_CD AND S.BID_NUM = HD.BID_NUM AND S.BID_CNT = HD.BID_CNT AND S.VOTE_CNT = VO.VOTE_CNT AND S.BID_STATUS = '300' AND S.DEL_FLAG = '0'), '-') AS SETTLE_VENDOR_CD ,NVL((SELECT GL.VENDOR_NM FROM STOCBDVO S LEFT JOIN STOCVNGL GL ON (S.GATE_CD = GL.GATE_CD AND S.VENDOR_CD = GL.VENDOR_CD) WHERE S.GATE_CD = HD.GATE_CD AND S.BUYER_CD = HD.BUYER_CD AND S.BID_NUM = HD.BID_NUM AND S.BID_CNT = HD.BID_CNT AND S.VOTE_CNT = VO.VOTE_CNT AND S.BID_STATUS = '300' AND S.DEL_FLAG = '0'), '-') AS SETTLE_VENDOR_NM ,NVL((SELECT S.BID_AMT FROM STOCBDVO S LEFT JOIN STOCVNGL GL ON (S.GATE_CD = GL.GATE_CD AND S.VENDOR_CD = GL.VENDOR_CD) WHERE S.GATE_CD = HD.GATE_CD AND S.BUYER_CD = HD.BUYER_CD AND S.BID_NUM = HD.BID_NUM AND S.BID_CNT = HD.BID_CNT AND S.VOTE_CNT = VO.VOTE_CNT AND S.BID_STATUS = '300' AND S.DEL_FLAG = '0'), null) AS SETTLE_AMT FROM STOCBDHD HD JOIN STOCBDPG PG ON (HD.GATE_CD = PG.GATE_CD AND HD.BUYER_CD = PG.BUYER_CD AND HD.BID_NUM = PG.BID_NUM AND HD.BID_CNT = PG.BID_CNT AND PG.DEL_FLAG = '0') JOIN STOCBDVO VO ON (PG.GATE_CD = VO.GATE_CD AND PG.BUYER_CD = VO.BUYER_CD AND PG.BID_NUM = VO.BID_NUM AND PG.BID_CNT = VO.BID_CNT AND PG.VOTE_CNT = VO.VOTE_CNT AND VO.VENDOR_CD = #{ses.companyCd} AND VO.DEL_FLAG = '0') LEFT JOIN STOCVNGL GL ON (VO.GATE_CD = GL.GATE_CD AND VO.VENDOR_CD = GL.VENDOR_CD) WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BID_STATUS IN ('1300', '2400', '2500') AND HD.BID_STATUS != '9999' AND HD.DEL_FLAG = '0' AND HD.SIGN_STATUS = 'E'
AND VO.VOTE_DATE >= #{BID_FROM_DATE} AND VO.VOTE_DATE <= #{BID_TO_DATE}
AND (CASE WHEN VO.BID_STATUS = '300' THEN '1' ELSE '0' END) = #{SETTLE_FLAG}
AND UPPER(HD.ANN_NO) LIKE '%' UPPER(#{ANN_NO}) '%'
AND UPPER(HD.ANN_ITEM) LIKE '%' UPPER(#{ANN_ITEM}) '%'
) A ORDER BY A.BID_NUM, A.BID_CNT, A.VOTE_CNT DESC

mapper.update:
UPDATE STOCBDAP
   SET INSU_STATUS        = 'DE'
     , GUAR_CANCEL_RMK    = #{GUAR_CANCEL_RMK}
     , GUAR_CANCEL_STATUS = 'J'
     , GUAR_CANCEL_REQ_DATE = SYSDATE
     , GUAR_REJECT_RMK = NULL
     , GUAR_CANCEL_REJECT_DATE = NULL
     , GUAR_CANCEL_CONFIRM_DATE = NULL
WHERE GATE_CD    = #{ses.gateCd}
AND BUYER_CD     = #{BUYER_CD}
AND BID_NUM      = #{BID_NUM}
AND BID_CNT      = #{BID_CNT}
AND VENDOR_CD    = #{VENDOR_CD}
